import { Controller, Get, Query } from '@nestjs/common';
import { LookupService } from './lookup.service';

@Controller('lookups')
export class LookupController {
  constructor(private readonly lookupService: LookupService) {}

  @Get('countries')
  async getCountries(@Query('filter') filter?: string) {
    return this.lookupService.getCountries(filter);
  }

  @Get('devices')
  async getDevices(@Query('filter') filter?: string) {
    return this.lookupService.getDevices(filter);
  }

  @Get('institutions')
  async getInstitutions(@Query('filter') filter?: string) {
    return this.lookupService.getInstitutions(filter);
  }
}

// lookup.service.ts
import { Injectable } from '@nestjs/common';

@Injectable()
export class LookupService {
  private countries = ['USA', 'Canada', 'Mexico']; // Fixed syntax error
  private devices = ['Laptop', 'Tablet', 'Smartphone'];
  private institutions = ['University A', 'College B', 'School C'];

  getCountries(filter?: string) {
    return this.filterData(this.countries, filter);
  }

  getDevices(filter?: string) {
    return this.filterData(this.devices, filter);
  }

  getInstitutions(filter?: string) {
    return this.filterData(this.institutions, filter);
  }

  private filterData(data: string[], filter?: string) {
    if (!filter) return data;
    return data.filter(item => item.toLowerCase().includes(filter.toLowerCase()));
  }
}
